reference_solution:
def caesar_cipher(text, shift):
    result = ""
    for ch in text:
        if ch.isalpha():
            base = ord('a') if ch.islower() else ord('A')
            result += chr((ord(ch) - base + shift) % 26 + base)
        else:
            result += ch
    return result

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_basic_shift(self):
        self.assertEqual(caesar_cipher("abc", 3), "def")

    def test_wrap_around(self):
        self.assertEqual(caesar_cipher("xyz", 3), "abc")

    def test_mixed_with_punctuation(self):
        self.assertEqual(caesar_cipher("Hello, World!", 5), "Mjqqt, Btwqi!")

    def test_hidden_zero_shift(self):
        self.assertEqual(caesar_cipher("abc", 0), "abc")

    def test_hidden_negative_shift(self):
        self.assertEqual(caesar_cipher("def", -3), "abc")

    def test_hidden_full_rotation(self):
        self.assertEqual(caesar_cipher("abc", 26), "abc")

    def test_hidden_empty_string(self):
        self.assertEqual(caesar_cipher("", 5), "")

    def test_hidden_non_alpha_only(self):
        self.assertEqual(caesar_cipher("123!@#", 5), "123!@#")

    def test_hidden_large_shift(self):
        self.assertEqual(caesar_cipher("abc", 52), "abc")

    def test_hidden_negative_wrap(self):
        self.assertEqual(caesar_cipher("abc", -3), "xyz")

    def test_hidden_uppercase_wrap(self):
        self.assertEqual(caesar_cipher("XYZ", 3), "ABC")

if __name__ == '__main__':
    unittest.main()
